#include <vector>
#include <algorithm>

using namespace std;

long long solve(vector<long long> prices, vector<long long> strategy, long long k) {
    int n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }
    long long max_profit = original_profit;

    int half_k = k / 2;

    vector<long long> prefix_strategy_p(n + 1, 0);
    vector<long long> prefix_p(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_strategy_p[i+1] = prefix_strategy_p[i] + strategy[i] * prices[i];
        prefix_p[i+1] = prefix_p[i] + prices[i];
    }

    for (int i = 0; i <= n - k; ++i) {
        int j = i + k;
        int first_half_start = i;
        int first_half_end = i + half_k;
        long long first_half_sum = prefix_strategy_p[first_half_end] - prefix_strategy_p[first_half_start];
        long long first_half_change = -first_half_sum;

        int second_half_start = i + half_k;
        int second_half_end = j;
        long long second_half_strategy_sum = prefix_strategy_p[second_half_end] - prefix_strategy_p[second_half_start];
        long long second_half_p_sum = prefix_p[second_half_end] - prefix_p[second_half_start];
        long long second_half_change = second_half_p_sum - second_half_strategy_sum;

        long long total_change = first_half_change + second_half_change;
        long long current_profit = original_profit + total_change;
        if (current_profit > max_profit) {
            max_profit = current_profit;
        }
    }

    return max_profit;
}
